// workloadFilterTransformer
// ----------------------

const rows = {{ dynamicChartTransformer.value || [] }};

// ----------------------
// Inputs
// ----------------------
const mode = {{ viewModeSelect.value || "top" }};
const topN = {{ Number(topNInput.value || 5) }};
const selectedGroups = {{ groupFilterSelect.value || [] }};
const category = {{ categorySelect4.value }};

// Capacity toggle
const SHOW_CAPACITY = {{ showCapacityLines.value === true }};

// ----------------------
// Capacity (weld inches / week)
// ----------------------
const CAPACITY_BY_SHOP = {
  "JWT Fab": 3000,
  "Polk Fab Shop": 1200
};

// ----------------------
// 1) Compute totals by group (Top N logic)
// ----------------------
const totalsByGroup = {};
rows.forEach(r => {
  const key = r.group_key || "Unassigned";
  const val = Number(r.hours || 0);
  totalsByGroup[key] = (totalsByGroup[key] || 0) + val;
});

// ----------------------
// 2) Sorted group list
// ----------------------
const allGroups = Object.entries(totalsByGroup)
  .sort((a, b) => b[1] - a[1])
  .map(([k]) => k);

// ----------------------
// 3) Active groups
// ----------------------
let activeGroups;
if (mode === "manual" && selectedGroups.length > 0) {
  activeGroups = selectedGroups;
} else {
  activeGroups = allGroups.slice(0, topN);
}

// ----------------------
// 4) Filter rows by group
// ----------------------
let filteredRows = rows.filter(r =>
  activeGroups.includes(r.group_key)
);

// ----------------------
// 5) Package → Project Filter
// ----------------------
if (category === "package_name") {
  let selectedProjects = {{ packageProjectFilter.value || [] }};
  if (!Array.isArray(selectedProjects)) {
    selectedProjects = [selectedProjects];
  }

  selectedProjects = selectedProjects.filter(Boolean);

  if (selectedProjects.length > 0) {
    filteredRows = filteredRows.filter(r =>
      selectedProjects.includes(r.project_name)
    );
  }
}

// ----------------------
// 6) Decide chart type
// ----------------------
const groupCount = activeGroups.length;
const isLow = ["assigned_shop", "material_type"].includes(category);
const isMedium = ["project_name", "job_number"].includes(category);
const isHigh = ["package_name"].includes(category);

let chartType = "line";

if (isLow) {
  if (groupCount <= 7) chartType = "line";
  else if (groupCount <= 20) chartType = "stacked_bar";
  else chartType = "bar";
} else if (isMedium) {
  if (mode === "manual" && groupCount <= 3) chartType = "line";
  else if (groupCount <= 7) chartType = "line";
  else if (groupCount <= 20) chartType = "stacked_bar";
  else chartType = "bar";
} else if (isHigh) {
  if (mode === "manual" && groupCount <= 2) chartType = "line";
  else if (groupCount <= 20) chartType = "stacked_bar";
  else chartType = "bar";
}

// ----------------------
// 7) Build capacity rows (optional)
// ----------------------
let capacityRows = [];

if (SHOW_CAPACITY) {
  // unique weekly buckets
  const buckets = Array.from(
    new Set(filteredRows.map(r => r.sortable_bucket))
  );

  activeGroups.forEach(group => {
    const capacity = CAPACITY_BY_SHOP[group];
    if (!capacity) return;

    buckets.forEach(bucket => {
      const refRow = filteredRows.find(
        r => r.sortable_bucket === bucket
      );

      capacityRows.push({
  group_key: `${group} Capacity`,
  hours: capacity,

  // 🔑 REQUIRED for chart X-axis
  display_bucket: refRow?.display_bucket ?? refRow?.x_axis_label_pretty,

  // still keep sortable bucket for ordering / reuse
  sortable_bucket: bucket,

  x_axis_label_pretty:
    refRow?.x_axis_label_pretty ?? bucket,

  // styling flags
  is_capacity: true,
  capacity_for: group
});

    });
  });
}

// ----------------------
// 8) Final rows
// ----------------------
const finalRows = [
  ...filteredRows,
  ...capacityRows
];

// ----------------------
// 9) Return
// ----------------------
return {
  rows: finalRows.map(r => ({
    ...r,
    x_axis_label_pretty: r.x_axis_label_pretty,
    sortable_bucket: r.sortable_bucket
  })),
  allGroups,
  activeGroups,
  chartType
};





